import heapq
class Solution:
    def minSideJumps(self, obstacles):
        n = len(obstacles)
        # Dijkstra over (point, lane) states; lane 1..3
        INF = float('inf')
        dist = [[INF] * 4 for _ in range(n)]
        dist[0][2] = 0
        pq = [(0, 0, 2)]
        while pq:
            d, p, lane = heapq.heappop(pq)
            if d > dist[p][lane]:
                continue
            if p == n - 1:
                return d
            # side jump at same point to another open lane
            for nl in (1, 2, 3):
                if nl != lane and obstacles[p] != nl:
                    nd = d + 1
                    if nd < dist[p][nl]:
                        dist[p][nl] = nd
                        heapq.heappush(pq, (nd, p, nl))
            # move forward on same lane if next point not blocked on this lane
            if p + 1 < n and obstacles[p + 1] != lane:
                if d < dist[p + 1][lane]:
                    dist[p + 1][lane] = d
                    heapq.heappush(pq, (d, p + 1, lane))
        return min(dist[n - 1][1:])

