class Solution:
    def minSideJumps(self, obstacles):
        INF = float('inf')
        cost = [INF, 1, 0, 1]
        for ob in obstacles:
            if ob:
                cost[ob] = INF
            best = min(cost[1], cost[2], cost[3])
            for lane in (1, 2, 3):
                if lane != ob and cost[lane] > best + 1:
                    cost[lane] = best + 1
        return min(cost[1], cost[2], cost[3])

