var minSideJumps = function(obstacles) {
    const INF = Infinity;
    const cost = [INF, 1, 0, 1];
    for (const ob of obstacles) {
        if (ob) cost[ob] = INF;
        const best = Math.min(cost[1], cost[2], cost[3]);
        for (let lane = 1; lane <= 3; lane++) {
            if (lane !== ob && cost[lane] > best + 1) cost[lane] = best + 1;
        }
    }
    return Math.min(cost[1], cost[2], cost[3]);
};
